// Разбираем апдейт от Max Trigger
const update = $input.item.json;

const updateType = update.update_type || '';

const isCallback = updateType === 'message_callback';
const isMessage  = updateType === 'message_created';
const isBotStart = updateType === 'bot_started' || updateType === 'message_chat_created';

let chatId, userId, text, callbackData, username, firstName;

if (isCallback) {
  const cb = update.callback || {};
  userId       = (cb.user && cb.user.user_id)  || '';
  username     = (cb.user && cb.user.username) || '';
  firstName    = (cb.user && cb.user.name)     || '';
  // chat_id может быть в message.recipient.chat_id или cb.message.recipient.chat_id
  chatId       = (cb.message && cb.message.recipient && cb.message.recipient.chat_id) ||
                 (cb.user && cb.user.user_id) || '';
  callbackData = cb.payload || '';
  text         = '';

} else if (isMessage) {
  const msg = update.message || {};
  userId    = (msg.sender && msg.sender.user_id) || '';
  username  = (msg.sender && msg.sender.username) || '';
  firstName = (msg.sender && msg.sender.name) || '';
  chatId    = (msg.recipient && msg.recipient.chat_id) || userId || '';
  text      = (msg.body && msg.body.text) || '';
  callbackData = '';

} else if (isBotStart) {
  userId    = (update.user && update.user.user_id) || '';
  username  = (update.user && update.user.username) || '';
  firstName = (update.user && update.user.name) || '';
  chatId    = update.chat_id || userId || '';
  text      = '';
  callbackData = '';

} else {
  chatId = userId = username = firstName = text = callbackData = '';
}

const isStart  = text === '/start' || isBotStart;

// Проверяем голосовое (аудио-аттачмент в Max)
const attachments = (update.message && update.message.body && update.message.body.attachments) || [];
const isVoice = attachments.some(a => a.type === 'audio');

// Сохраняем оригинальный update для дальнейшего использования
return [{
  json: {
    chatId,
    userId,
    username,
    firstName,
    text,
    callbackData,
    isCallback,
    isMessage,
    isStart,
    isVoice,
    updateType,
    _rawUpdate: update
  }
}];

