// Скачиваем аудио-файл из Max
// В Max аудио приходит как аттачмент типа 'audio' с полем url или token
const update = $('Max Trigger').item.json;
const attachments = (update.message && update.message.body && update.message.body.attachments) || [];
const audioAtt = attachments.find(a => a.type === 'audio');

if (!audioAtt || !audioAtt.payload) {
  throw new Error('Аудио аттачмент не найден');
}

// Возвращаем url для скачивания
return [{
  json: {
    ...update,
    audioUrl: audioAtt.payload.url || '',
    audioToken: audioAtt.payload.token || ''
  }
}];

const output = $input.item.json.output || '';

// Попытаемся найти JSON в ответе
const jsonMatch = output.match(/\{[\s\S]*\"onboarding_complete\"[\s\S]*\}/);

if (jsonMatch) {
  try {
    const parsed = JSON.parse(jsonMatch[0]);
    if (parsed.onboarding_complete === true) {
      const preferredTime = parsed.preferred_time || '09:00';
      return [{
        json: {
          is_onboarding_done: true,
          first_name: parsed.first_name || '',
          birth_date: parsed.birth_date || '',
          city: parsed.city || '',
          preferred_time: preferredTime,
          timezone: parsed.timezone || 'Europe/Moscow',
          message: `${parsed.first_name}, всё готово 🌟\n\nКаждый день в ${preferredTime} буду присылать тебе персональный прогноз. Можешь прямо сейчас написать, что тебя интересует — прогноз на сегодня, неделю или месяц 🔮`
        }
      }];
    }
  } catch (e) {
    // не JSON — продолжаем диалог
  }
}

return [{
  json: {
    is_onboarding_done: false,
    message: output
  }
}];

