// В Max нет прямого аналога getChatMember для проверки подписки на канал.
// Этот узел является заглушкой — всегда возвращает 'subscribed'.
// Если нужна реальная проверка подписки — реализуйте собственную логику
// (например, через базу данных или другой механизм).
return [{ json: { result: { status: 'member' } } }];

// Заглушка проверки подписки для callback-ветки.
// Max API не поддерживает проверку членства в канале.
// Всегда возвращаем 'subscribed'.
return [{ json: { result: { status: 'member' } } }];

// Заглушка проверки подписки для текстовой ветки.
// Max API не поддерживает проверку членства в канале.
// Всегда возвращаем 'subscribed'.
return [{ json: { result: { status: 'member' } } }];

const output = $input.item.json.output || '';

if (output.includes('ДАННЫЕ_СОБРАНЫ')) {
  // Parse collected data
  const nameMatch = output.match(/имя:\s*(.+)/i);
  const dateMatch = output.match(/дата_рождения:\s*(.+)/i);
  const cityMatch = output.match(/город:\s*(.+)/i);

  const otherName = nameMatch ? nameMatch[1].trim() : '';
  const otherDate = dateMatch ? dateMatch[1].trim() : '';
  const otherCity = cityMatch ? cityMatch[1].trim() : '';

  return [{
    json: {
      ...$input.item.json,
      dataReady: true,
      otherName,
      otherDate,
      otherCity,
      messageToUser: null
    }
  }];
} else {
  // Still collecting — pass through agent's question to user
  return [{
    json: {
      ...$input.item.json,
      dataReady: false,
      messageToUser: output
    }
  }];
}

